mapper.select:
SELECT trai.write_year, trai.doc_no, trai.doc_seq, trai.impl_write_year, trai.impl_doc_no, trai.impl_doc_seq
  FROM esg.tb_risk_assessment_plan trap
  LEFT JOIN esg.tb_risk_assessment_implementation trai
    ON trai.write_year = trap.write_year
   AND trai.doc_no = trap.doc_no
 WHERE trap.write_year = #{writeYear}
   AND trap.doc_no = #{docNo}
   AND trai.impl_write_year IS NOT NULL
   AND trap.comp_id = #{compId}

SELECT CASE WHEN a.hazards_type = 'factor_1' THEN '기계적 요인' WHEN a.hazards_type = 'factor_2' THEN '전기적 요인' WHEN a.hazards_type = 'factor_3' THEN '화학(물질)적 요인' WHEN a.hazards_type = 'factor_4' THEN '생물학적요인' WHEN a.hazards_type = 'factor_5' THEN '작업특성 요인' WHEN a.hazards_type = 'factor_6' THEN '작업환경 요인' END AS hazards_title, a.hazards_type, j.plan_nm, j.risk_assessment_standards, d.hazards_classification, -- hazards_type에 따른 분류 정보 -- 요인 정보 'RAP' AS doc_type, b.doc_no, b.doc_seq, b.write_year, i.class_nm, b.hazards_classification AS impl_hazards_classification, b.hazards_cause, b.hazards_factor, b.related_evidence, b.use_yn AS impl_use_yn, b.process_id, coalesce(b.prcs_work_id, 0) AS prcs_work_id, d1.minor_nm as frequency_score, d2.minor_nm as impact_score, d3.minor_nm as risk_score, b.current_safety_measures, b.created_at, d4.minor_nm as after_frequency_score, d5.minor_nm as after_impact_score, d6.minor_nm as after_risk_score, -- 감소대책 정보 'RAP' as reduction_doc_type, case when f.DOC_SEQ_DETAIL is null then null else (DENSE_RANK() OVER ( PARTITION BY c.doc_no, d.doc_seq ORDER BY d.write_year, e.class_id DESC, f.doc_seq_detail )) END AS resultCnt, f.doc_no, f.doc_seq, f.doc_seq_detail, f.reduction_measures, f.expected_date, f.completed_date, f.impl_content, f.use_yn AS reduction_use_yn, f.created_at AS redcution_created_at, -- 담당자 정보 g.doc_seq_detail2, g.hr_id, h.hr_nm FROM ( SELECT hazards_type from esg.tb_risk_assessment_implementation where write_year = #{writeYear} AND doc_type = 'RAP' AND doc_no = #{docNo} AND prcs_work_id = #{prcsWorkId} UNION SELECT b.hazards_type FROM ESG.tb_classification_hazards a LEFT JOIN esg.tb_classification_hazards_detail b ON a.write_year = b.write_year AND a.doc_type = b.doc_type AND a.doc_no = b.doc_no WHERE a.use_yn = 'Y' AND a.process_id = #{processId} AND a.process_work_rev_no = #{revNo} AND a.comp_id = #{compId} AND a.write_year = #{writeYear} ) a LEFT JOIN esg.tb_risk_assessment_implementation b ON b.hazards_type = a.hazards_type AND write_year = #{writeYear} AND doc_type = 'RAP' AND doc_no = #{docNo}
AND prcs_work_id = #{prcsWorkId}
LEFT JOIN esg.tb_classification_hazards c ON c.use_yn = 'Y' AND c.process_id = #{processId} AND c.write_year = #{writeYear}
AND c.process_work_rev_no = #{revNo} AND c.comp_id = #{compId}
LEFT JOIN esg.tb_classification_hazards_detail d ON d.write_year = c.write_year AND d.doc_type = c.doc_type AND d.doc_no = c.doc_no AND d.hazards_type = a.hazards_type LEFT JOIN esg.tb_classification_hazards_factor_mgmt e ON e.factor_id = d.hazards_type AND e.class_id = d.hazards_classification LEFT JOIN esg.tb_risk_assessment_implementation_reduction f ON f.write_year = b.write_year AND f.doc_type = b.doc_type AND f.doc_no = b.doc_no AND f.doc_seq = b.doc_seq LEFT JOIN esg.tb_risk_assessment_implementation_reduction_hr g ON g.write_year = f.write_year AND g.doc_type = f.doc_type AND g.doc_no = f.doc_no AND g.doc_seq = f.doc_seq AND g.doc_seq_detail = f.doc_seq_detail LEFT JOIN esg.tb_hr_info h ON h.hr_id = g.hr_id LEFT JOIN esg.tb_classification_hazards_factor_mgmt i ON i.factor_id = b.hazards_type AND i.class_id = b.hazards_classification LEFT JOIN esg.tb_risk_assessment_plan j ON j.doc_no = #{docNo} AND j.write_year = #{writeYear} AND j.comp_id = #{compId} LEFT JOIN esg.tb_common_d d1 ON d1.major_cd = 'C0038' AND d1.minor_cd = b.frequency_score LEFT JOIN esg.tb_common_d d2 ON d2.major_cd = 'C0039' AND d2.minor_cd = b.impact_score LEFT JOIN esg.tb_common_d d3 ON d3.major_cd = 'C0040' AND d3.minor_cd = b.risk_score LEFT JOIN esg.tb_common_d d4 ON d4.major_cd = 'C0038' AND d4.minor_cd = b.after_frequency_score LEFT JOIN esg.tb_common_d d5 ON d5.major_cd = 'C0039' AND d5.minor_cd = b.after_impact_score LEFT JOIN esg.tb_common_d d6 ON d6.major_cd = 'C0040' AND d6.minor_cd = b.after_risk_score ORDER BY a.hazards_type ASC, e.class_id DESC, b.doc_seq ASC, f.doc_seq_detail ASC

insert.selectKey:
	SELECT coalesce(#{docSeq}, LPAD((COALESCE(MAX(doc_seq::INTEGER), 0) + 1)::TEXT, 5, '0')) AS docSeq
      FROM ESG.TB_RISK_ASSESSMENT_IMPLEMENTATION
	 WHERE write_year = #{writeYear}
	   AND doc_type = #{docType}
	   AND doc_no = #{docNo}

insert.foreach:
    	INSERT INTO ESG.TB_RISK_ASSESSMENT_IMPLEMENTATION_REDUCTION_HR (
			WRITE_YEAR,
			DOC_TYPE,
			DOC_NO,
			DOC_SEQ,
			DOC_SEQ_DETAIL,
			DOC_SEQ_DETAIL2,
			HR_ID,
			CREATED_AT,
			CREATED_BY
		) VALUES (
			#{writeYear},
			#{docType},
			#{docNo},
			#{docSeq},
			#{docSeqDetail},
			(
				SELECT LPAD((COALESCE(MAX(doc_seq_detail2::INTEGER), 0) + 1)::TEXT, 5, '0') AS docSeqDetail2
			      FROM ESG.TB_RISK_ASSESSMENT_IMPLEMENTATION_REDUCTION_HR
				 WHERE write_year = #{writeYear}
				   AND doc_type = #{docType}
				   AND doc_no = #{docNo}
				   AND doc_seq = #{docSeq}
				   AND doc_seq_detail = #{docSeqDetail} 
			),
			#{item.hrId},
			NOW(),
			#{createdBy}
		)

mapper.delete:
DELETE FROM ESG.TB_RISK_ASSESSMENT_IMPLEMENTATION
WHERE WRITE_YEAR = #{writeYear}
AND DOC_TYPE = #{docType}
AND DOC_NO = #{docNo}

DELETE FROM ESG.TB_RISK_ASSESSMENT_IMPLEMENTATION_REDUCTION
WHERE WRITE_YEAR = #{writeYear}
AND DOC_TYPE = #{docType}
AND DOC_NO = #{docNo}

DELETE FROM ESG.TB_RISK_ASSESSMENT_IMPLEMENTATION_REDUCTION_HR
WHERE WRITE_YEAR = #{writeYear}
AND DOC_TYPE = #{docType}
AND DOC_NO = #{docNo}

	DELETE FROM ESG.TB_RISK_ASSESSMENT_IMPLEMENTATION_REDUCTION_HR
     WHERE WRITE_YEAR = #{writeYear}
       AND DOC_TYPE = #{docType}
       AND DOC_NO = #{docNo}
       AND DOC_SEQ = #{docSeq}
       AND DOC_SEQ_DETAIL = #{docSeqDetail}

DELETE FROM esg.tb_approval_info
 WHERE target_type = #{targetType}
 AND target_id = #{targetId}
 AND type = 'worker'
